public class FloydWarshall {

    public int[][] allPairsShortestPath(int[][] graph) {
        int V = graph.length;
        int[][] dist = new int[V][V];

        // Initialize dist with direct edges (Integer.MAX_VALUE/2 for no edge)
        for (int i = 0; i < V; i++)
            for (int j = 0; j < V; j++)
                dist[i][j] = graph[i][j];

        // TODO: triple nested loop: for each intermediate k,
        //       for each i, for each j: update dist[i][j] via k

        return dist;
    }

    public void print(int[][] dist) {
        int V = dist.length;
        for (int i = 0; i < V; i++) {
            for (int j = 0; j < V; j++) {
                if (dist[i][j] >= Integer.MAX_VALUE / 2)
                    System.out.printf("%5s", "INF");
                else
                    System.out.printf("%5d", dist[i][j]);
            }
            System.out.println();
        }
    }

    public static void main(String[] args) {
        final int INF = Integer.MAX_VALUE / 2;
        int[][] g = {
            {0,   3,   INF, 7  },
            {8,   0,   2,   INF},
            {5,   INF, 0,   1  },
            {2,   INF, INF, 0  }
        };
        FloydWarshall fw = new FloydWarshall();
        int[][] dist = fw.allPairsShortestPath(g);
        fw.print(dist);
    }
}
